                          Tasks="filteredInProgress"
                          ShowMoveLeft="true"
                          ShowMoveRight="true"
                          OnMoveLeft="id => MoveTask(id, &quot;To Do&quot;)"
                          OnMoveRight="id => MoveTask(id, &quot;Done&quot;)"
                          OnTaskCreated="data => CreateTask(data, &quot;In Progress&quot;)" />

            <KanbanColumn ColumnName="Done"
                          Tasks="filteredDone"
                          ShowMoveLeft="true"
                          ShowMoveRight="false"
                          OnMoveLeft="id => MoveTask(id, &quot;In Progress&quot;)"
                          OnTaskCreated="data => CreateTask(data, &quot;Done&quot;)" />
        </div>
    }
</div>

@code {
    private List<TaskItem> tasks = new();
    private bool isLoading = true;
    private string? errorMessage;
    private string searchText = "";

    // Unfiltered column lists (used for stats)
    private List<TaskItem> todoTasks => tasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => tasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => tasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => tasks.Where(t => t.DueDate < DateTime.Today).ToList();

    // Filtered column lists (used for display)
    private List<TaskItem> filteredTodo => Filter(todoTasks);
    private List<TaskItem> filteredInProgress => Filter(inProgressTasks);
    private List<TaskItem> filteredDone => Filter(doneTasks);

    private List<TaskItem> Filter(List<TaskItem> source)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return source;

        return source.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = tasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                tasks = tasks.Select(t => t.Id == taskId ? t with { Status = newStatus } : t).ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
        // The service might not return the correct status for the column, so ensure it matches
        tasks.Add(newTask with { Status = status });
    }
}
