{"file_text": ".board-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 1rem;
}

/* Stats bar */
.board-stats {
    display: flex;
    gap: 1rem;
    margin-bottom: 1rem;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.stat {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 80px;
}

.stat-value {
    font-size: 1.5rem;
    font-weight: 700;
}

.stat-label {
    font-size: 0.8rem;
    color: #6c757d;
}

.stat-overdue .stat-value {
    color: #dc3545;
}

