    border-radius: 12px;
    padding: 0.1rem 0.5rem;
    font-size: 0.8rem;
    font-weight: 600;
}

.column-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.column-footer {
    margin-top: 0.75rem;
